module shift_register (
    input clk,
    input sclr,
    input shift_en,
    input data,
    output [3:0] q );reg [3:0] invalid_shift_reg;

always @(posedge clk) begin
    if (sclr)
        invalid_shift_reg <= 4'b0000;
    else if (shift_en)
        invalid_shift_reg <= {invalid_shift_reg[2:0], data};
end

assign q = invalid_shift_reg;

endmodule
